define i64 @test_mul_add_by_2(i64 %x) {
  %x1 = add i64 %x, 2
  %mul = mul nuw i64 %x, 3
  %max = call i64 @llvm.umax.i64(i64 %mul, i64 %x1)
  ret i64 %max
}

